#include <iostream>

template <typename T>
T getLarger(T val1, T val2) {
    return val1 > val2 ? val1 : val2;
}

int main() {
    int int1 = 10; int int2 = 25;
    std::cout << getLarger(int1, int2) << std::endl;

    double double1 = 3.14; double double2 = 2.718;
    std::cout << getLarger(double1, double2) << std::endl;

    const char* str1 = "apple"; const char* str2 = "banana";
    std::cout << getLarger(str1, str2) << std::endl;

    const char* str3 = "zebra"; const char* str4 = "aardvark";
    std::cout << getLarger(str3, str4) << std::endl;

    return 0;
}
